import express from 'express';
import { db } from '../../lib/db';
import { requireAuth } from '../../middleware/auth';
import { writeAudit } from '../../lib/audit';

const router = express.Router();

router.get('/api/cases/:id', requireAuth, async (req, res) => {
  const caseId = req.params.id;
  const actor = req.user.email;

  const row = await db('cases')
    .select('id', 'title', 'severity', 'status', 'owner_email', 'summary', 'created_at')
    .where({ id: caseId })
    .first();

  if (!row) {
    return res.status(404).json({ error: 'case_not_found' });
  }

  await writeAudit({
    action: 'case.view',
    actor,
    target_type: 'case',
    target_id: caseId,
    metadata: { source: 'web_console', trace_tag: 'SOC-AUDIT-TRACE' }
  });

  return res.json({ case: row });
});

export default router;

